    IFS=',' read -ra Y_EDGES <<< "$Y_EDGES_STR"

    NUM_Y_BINS=$(( ${#Y_EDGES[@]} - 1 ))

    # Loop over y-bin ranges for this x-bin
    for ((j=0; j<NUM_Y_BINS; j++)); do
        Y_LOW=$(echo ${Y_EDGES[$j]} | xargs)
        Y_HIGH=$(echo ${Y_EDGES[$((j+1))]} | xargs)

        PARAM_NAME="enu_erec_minus_enu_${COUNT}"

        cat <<EOL >> $OUTPUT_FILE
- Systematic:
    SampleNames: ["ND*", "FD*"]
    Error: 0.5
    FlatPrior: false
    KinematicCuts:
    - TrueNeutrinoEnergy:
      - $ENE_LOW
      - $ENE_HIGH
    - Enubias:
      - $Y_LOW
      - $Y_HIGH
    Names:
      FancyName: $PARAM_NAME
      ParameterName: $PARAM_NAME
    ParameterBounds:
    - 0.0
    - 4.0
    ParameterValues:
      Generated: 1.0
      PreFitValue: 1.0
    StepScale:
      MCMC: 1.0
    Type: Norm
    ParameterGroup: Xsec
EOL

        echo "$PARAM_NAME, $ENE_LOW, $ENE_HIGH, $Y_LOW, $Y_HIGH" >> $PARAM_LIST_FILE
        COUNT=$((COUNT+1))
    done
done

echo " Config file generated: $OUTPUT_FILE"
echo "Parameter list generated: $PARAM_LIST_FILE"
